const dryRun=process.argv.includes('--dry-run');
const skipExternal=process.env.DROP8_PATCH_SKIP_EXTERNAL_VALIDATION==='1';
const forceFail=process.env.DROP8_PATCH_FORCE_VALIDATION_FAIL==='1';

type Change=(typeof changes)[number];
type PlanItem={change:Change;state:'applied'|'pending';mode:'created'|'baseline'|'merged'|'already';next:string;current:string;useCrLf:boolean};

function normalize(text:string){return text.replace(/^\uFEFF/,'').replace(/\r\n/g,'\n').replace(/\r/g,'\n');}
function hashText(text:string){return createHash('sha256').update(normalize(text),'utf8').digest('hex');}
function readText(path:string){return readFileSync(path,'utf8');}
function decode(data:string){return gunzipSync(Buffer.from(data,'base64')).toString('utf8');}
function count(text:string,needle:string){return text.split(needle).length-1;}
function isRoot(dir:string){return existsSync(join(dir,'package.json'))&&existsSync(join(dir,'shared','src','index.ts'))&&existsSync(join(dir,'server','src','rooms','Drop8Room.ts'))&&existsSync(join(dir,'client','src','network.ts'));}
function ancestors(start:string){const result:string[]=[];let current=resolve(start);for(let i=0;i<12;i++){if(!result.includes(current))result.push(current);const parent=dirname(current);if(parent===current)break;current=parent;}return result;}
function findRoot(){const scriptDir=dirname(fileURLToPath(import.meta.url));for(const candidate of [...ancestors(process.cwd()),...ancestors(scriptDir)])if(isRoot(candidate))return candidate;throw new Error('DROP 8 프로젝트 루트를 찾지 못했습니다. 패치 파일을 프로젝트 루트에서 실행하세요.');}
function stamp(){return new Date().toISOString().replace(/[:.]/g,'-');}
function command(label:string,cmd:string,root:string){console.log(`[${PATCH}] ${label}`);const result=spawnSync(cmd,{cwd:root,stdio:'inherit',shell:true,env:process.env});if(result.error)throw result.error;if(result.status!==0)throw new Error(`명령 실패 (exit=${result.status}): ${cmd}`);}

function mergeThreeWay(current:string,base:string,patched:string,relative:string,tempRoot:string){
  const safe=relative.replace(/[\\/:*?"<>|]/g,'_');
  const currentPath=join(tempRoot,`${safe}.current`),basePath=join(tempRoot,`${safe}.base`),patchedPath=join(tempRoot,`${safe}.patched`);
  writeFileSync(currentPath,normalize(current),'utf8');writeFileSync(basePath,normalize(base),'utf8');writeFileSync(patchedPath,normalize(patched),'utf8');
  const result=spawnSync('git',['merge-file','-p','--diff3','--',currentPath,basePath,patchedPath],{encoding:'utf8',maxBuffer:64*1024*1024,windowsHide:true});
  if(result.error)throw new Error(`${relative}: Git 3-way merge 실행 실패: ${result.error.message}`);
  if(result.status===1){const conflictPath=join(tempRoot,`${safe}.CONFLICT.txt`);writeFileSync(conflictPath,result.stdout||'','utf8');throw new Error(`${relative}: 현재 수동 수정과 Refactor 016C 수정이 같은 구간에서 충돌했습니다. 원본은 변경하지 않았습니다.`);}
  if(result.status!==0)throw new Error(`${relative}: Git 3-way merge 실패 (exit=${result.status}): ${String(result.stderr||'').trim()}`);
  const merged=normalize(result.stdout||'');
  if(merged.includes('<<<<<<<')||merged.includes('=======')||merged.includes('>>>>>>>'))throw new Error(`${relative}: merge 충돌 표식이 감지되었습니다.`);
  return merged;
}

function importLocals(text:string){
  const locals:string[]=[];
  const named=/import\s+(?:type\s+)?\{([\s\S]*?)\}\s+from\s+['"][^'"]+['"]/g;
  for(const match of text.matchAll(named))for(const raw of match[1].split(',')){const item=raw.trim().replace(/^type\s+/,'');if(!item)continue;const parts=item.split(/\s+as\s+/);locals.push((parts[1]??parts[0]).trim());}
  const defaults=/^import\s+(?!type\b)([A-Za-z_$][\w$]*)\s*(?:,|from)/gm;
  for(const match of text.matchAll(defaults))locals.push(match[1]);
  const namespaces=/^import\s+\*\s+as\s+([A-Za-z_$][\w$]*)\s+from/gm;
  for(const match of text.matchAll(namespaces))locals.push(match[1]);
  return locals;
}
function validateDuplicateDeclarations(text:string,file:string){
  const names=[...importLocals(text)];
  const declarations=/^(?:export\s+)?(?:declare\s+)?(?:const|let|var|function|class|interface|type|enum)\s+([A-Za-z_$][\w$]*)/gm;
  for(const match of text.matchAll(declarations))names.push(match[1]);
  const seen=new Set<string>();
  for(const name of names){if(seen.has(name))throw new Error(`${file}: 최상위 식별자 '${name}' 중복 선언`);seen.add(name);}
}
function validateRelativeImports(root:string,relative:string,text:string){
  const pattern=/(?:from\s+|import\s*\()\s*['"](\.[^'"]+)['"]/g;
  for(const match of text.matchAll(pattern)){
    const spec=match[1];let target=resolve(dirname(join(root,relative)),spec);
    const candidates=[target];if(extname(target)==='.js')candidates.push(target.slice(0,-3)+'.ts');if(!extname(target))candidates.push(target+'.ts',target+'.tsx',join(target,'index.ts'));
    if(!candidates.some((candidate)=>existsSync(candidate)))throw new Error(`${relative}: 상대 import 확인 실패 '${spec}'`);
  }
}
function getText(root:string,planned:Map<string,string>,relative:string){return planned.get(relative)??readText(join(root,relative));}

function captureCriticalShared(text:string){
  const patterns:{name:string,re:RegExp}[]=[
    {name:'bazooka projectileSpeed',re:/bazooka:\{[^\n]*projectileSpeed:(\d+(?:\.\d+)?)/},
    {name:'supply triggerZoneStage',re:/triggerZoneStage:(\d+)/},
    {name:'supply weights',re:/bazookaWeight:(\d+),flamethrowerWeight:(\d+)/},
    {name:'flamethrower tick damage',re:/playerDamagePerTick:(\d+),vehicleDamagePerTick:(\d+),fuelPerTick:(\d+)/},
    {name:'bazooka vehicle damage',re:/directVehicleDamage:(\d+),maxSplashVehicleDamage:(\d+),minSplashVehicleDamage:(\d+),structureDamage:(\d+)/},
  ];
  return patterns.map(({name,re})=>{const m=re.exec(text);if(!m)throw new Error(`shared/src/index.ts: 기존 핵심 설정 '${name}'을 찾지 못했습니다.`);return {name,value:m.slice(1).join('|')};});
}
function packageVersions(root:string){
  const client=JSON.parse(readText(join(root,'client/package.json')));
  const server=JSON.parse(readText(join(root,'server/package.json')));
  const sdk=String(client.dependencies?.['@colyseus/sdk']??'');
  const core=String(server.dependencies?.['@colyseus/core']??'');
  const schema=String(server.dependencies?.['@colyseus/schema']??'');
  const testingSdk=String(server.devDependencies?.['@colyseus/sdk']??'');
  if(!sdk.includes('0.17')||!core.includes('0.17')||!testingSdk.includes('0.17')||!schema.includes('4.0'))throw new Error(`Colyseus 패키지 계열 검증 실패: sdk=${sdk}, core=${core}, schema=${schema}, server-sdk=${testingSdk}`);
  return `client sdk ${sdk} · server core ${core} · schema ${schema} · test sdk ${testingSdk}`;
}
function playerWireFieldCount(schema:string){
  const block=/export class PlayerState extends Schema \{([\s\S]*?)\n\}/.exec(schema)?.[1];
  if(!block)throw new Error('PlayerState 선언을 찾지 못했습니다.');
  return [...block.matchAll(/@type\(/g)].length;
}
function validateContent(root:string,planned:Map<string,string>,criticalBefore:{name:string,value:string}[]){
  const required:[string,string][]=[
    ['server/src/rooms/schema.ts',MARKER],
    ['server/src/rooms/Drop8Room.ts',MARKER],
    ['client/src/network.ts',MARKER],
    ['client/src/main.ts',MARKER],
    ['server/tests/room.test.ts',MARKER],
    ['server/tests/refactor016-client-source.test.ts',MARKER],
    ['server/tests/refactor016c-player-state-sync.test.ts',MARKER],
    ['server/src/rooms/Drop8Room.ts',"this.onMessage('soloClientReady'"],
    ['server/src/rooms/Drop8Room.ts','scheduleSoloStartFallback'],
    ['client/src/network.ts',"callbacks.onAdd('players'"],
    ['client/src/network.ts','return keyId||valueId'],
    ['client/src/network.ts','waitForLocalPlayer'],
    ['client/src/main.ts',"net.send('soloClientReady')"],
    ['server/tests/refactor016c-player-state-sync.test.ts','keeps PlayerState inside the 64-field wire limit'],
  ];
  for(const [relative,needle] of required){const path=join(root,relative);if(!planned.has(relative)&&!existsSync(path))throw new Error(`내장 검증 실패: ${relative} 없음`);if(!getText(root,planned,relative).includes(needle))throw new Error(`내장 검증 실패: ${relative} 에서 '${needle}' 확인 불가`);}
  const schema=getText(root,planned,'server/src/rooms/schema.ts');
  const fields=playerWireFieldCount(schema);
  if(fields!==64)throw new Error(`PlayerState 동기화 필드 제한 검증 실패: ${fields}/64`);
  if(/@type\('string'\)\s+id='';\s*\n\s*@type\('string'\)\s+name=''/.test(schema))throw new Error('PlayerState.id가 아직 네트워크 필드로 선언되어 있습니다.');
  const network=getText(root,planned,'client/src/network.ts');
  if(network.includes('DROP8_PLAYER_SYNC_HOTFIX_016B'))throw new Error('실패한 016B 임시 동기화 코드가 남아 있습니다.');
  if(network.includes('for(const delay of [0,50,150,400])'))throw new Error('고정 지연 재조회 코드가 남아 있습니다.');
  if(count(network,"callbacks.onAdd('players'")!==1)throw new Error('players onAdd 구독 중복 또는 누락');
  if(count(network,"callbacks.onRemove('players'")!==1)throw new Error('players onRemove 구독 중복 또는 누락');
  const room=getText(root,planned,'server/src/rooms/Drop8Room.ts');
  if(count(room,"this.onMessage('soloClientReady'")!==1)throw new Error('soloClientReady 메시지 핸들러 중복 또는 누락');
  if(/if\(this\.state\.soloMode&&p\.host&&this\.state\.phase==='LOBBY'\)\{\s*p\.ready=true;\s*this\.fillAi\(\);\s*this\.beginMatch\(\);/.test(room))throw new Error('솔로 onJoin 즉시 AI 생성 코드가 남아 있습니다.');
  const main=getText(root,planned,'client/src/main.ts');
  if(count(main,"net.send('soloClientReady')")!==1)throw new Error('soloClientReady 클라이언트 전송 중복 또는 누락');
  const shared=getText(root,planned,'shared/src/index.ts');
  const criticalAfter=captureCriticalShared(shared);
  for(const before of criticalBefore){const after=criticalAfter.find((item)=>item.name===before.name);if(!after||after.value!==before.value)throw new Error(`기존 수동 밸런스 보존 실패: ${before.name} (${before.value} -> ${after?.value??'missing'})`);}
  packageVersions(root);
  for(const change of changes){const text=getText(root,planned,change.path);if(change.path.endsWith('.ts')||change.path.endsWith('.tsx')){validateDuplicateDeclarations(text,change.path);if(change.create&&change.path.includes('/tests/'))validateRelativeImports(root,change.path,text);}}
}

function buildPlan(root:string,tempRoot:string){
  const plan:PlanItem[]=[];
  for(const change of changes){
    const target=join(root,change.path),exists=existsSync(target),after=normalize(decode(change.afterData));
    if(change.create){
      if(!exists){plan.push({change,state:'pending',mode:'created',next:after,current:'',useCrLf:false});continue;}
      const current=readText(target);
      if(hashText(current)===change.afterHash||current.includes(MARKER)){plan.push({change,state:'applied',mode:'already',next:normalize(current),current,useCrLf:current.includes('\r\n')});continue;}
      throw new Error(`${change.path}: 신규 테스트 파일 이름과 같은 다른 파일이 이미 존재합니다.`);
    }
    if(!exists)throw new Error(`${change.path}: 기준 파일이 없습니다.`);
    const current=readText(target),base=normalize(decode(change.beforeData)),currentNorm=normalize(current);
    if(hashText(currentNorm)===change.afterHash){plan.push({change,state:'applied',mode:'already',next:currentNorm,current,useCrLf:current.includes('\r\n')});continue;}
    const merged=mergeThreeWay(currentNorm,base,after,change.path,tempRoot);
    if(merged===currentNorm){plan.push({change,state:'applied',mode:'already',next:merged,current,useCrLf:current.includes('\r\n')});continue;}
    plan.push({change,state:'pending',mode:hashText(currentNorm)===change.beforeHash?'baseline':'merged',next:merged,current,useCrLf:current.includes('\r\n')});
  }
  return plan;
}

const root=findRoot();process.chdir(root);console.log(`[${PATCH}] 프로젝트 루트: ${root}`);
const tempRoot=mkdtempSync(join(tmpdir(),'drop8-ref016c-'));
try{
  const criticalBefore=captureCriticalShared(readText(join(root,'shared/src/index.ts')));
  const versions=packageVersions(root);
  const plan=buildPlan(root,tempRoot);
  const applied=plan.filter((item)=>item.state==='applied'),pending=plan.filter((item)=>item.state==='pending');
  const planned=new Map<string,string>(plan.map((item)=>[item.change.path,item.next]));
  if(applied.length===plan.length){validateContent(root,new Map(),criticalBefore);console.log(`[${PATCH}] 이미 적용되어 있습니다.`);console.log(`[${PATCH}] ${versions}`);process.exit(0);}
  if(applied.length&&pending.length)throw new Error(`부분 적용 상태 감지: 적용 완료 ${applied.length}개 / 적용 대기 ${pending.length}개. 이전 실패 백업 또는 Git 상태를 확인하세요.`);
  validateContent(root,planned,criticalBefore);
  const mergedCount=pending.filter((item)=>item.mode==='merged').length;
  console.log(`[${PATCH}] 기준 검증 성공: ${pending.length}개 적용 예정 · 로컬 수정 병합 ${mergedCount}개`);
  console.log(`[${PATCH}] 실제 원인 수정: PlayerState 65→64 동기화 필드 · MapSchema key 권위 ID · 솔로 2단계 시작`);
  console.log(`[${PATCH}] 패키지 확인: ${versions}`);
  console.log(`[${PATCH}] 보존 확인: ${criticalBefore.map((item)=>`${item.name}=${item.value}`).join(' · ')}`);
  if(dryRun){console.log(`[${PATCH}] dry-run 성공: 파일을 변경하지 않았습니다.`);process.exit(0);}

  const backupRoot=join(root,'patch_backups',BACKUP_NAME,stamp());mkdirSync(backupRoot,{recursive:true});
  const manifest:{path:string;existed:boolean}[]=[];
  try{
    for(const item of plan){
      const target=join(root,item.change.path),existed=existsSync(target),backup=join(backupRoot,'preimage',item.change.path);
      if(existed){mkdirSync(dirname(backup),{recursive:true});copyFileSync(target,backup);}
      manifest.push({path:item.change.path,existed});
    }
    writeFileSync(join(backupRoot,'manifest.json'),JSON.stringify({patch:PATCH,createdAt:new Date().toISOString(),files:manifest,criticalBefore,versions},null,2),'utf8');
    for(const item of pending){
      const target=join(root,item.change.path);mkdirSync(dirname(target),{recursive:true});
      let next=item.next;if(item.useCrLf)next=next.replace(/\n/g,'\r\n');
      writeFileSync(target,next,'utf8');
    }
    for(const item of pending)if(normalize(readText(join(root,item.change.path)))!==normalize(item.next))throw new Error(`변경 후 내용 검증 실패: ${item.change.path}`);
    validateContent(root,new Map(),criticalBefore);
    if(forceFail)throw new Error('DROP8_PATCH_FORCE_VALIDATION_FAIL=1 강제 실패');
    if(skipExternal)console.log(`[${PATCH}] 실행기 자체 검증용 외부 명령 생략`);
    else{
      command('pnpm run typecheck','pnpm run typecheck',root);
      command('pnpm run lint','pnpm run lint',root);
      command('Refactor 016C SDK 동기화 테스트','pnpm --filter @drop8/server exec vitest run tests/refactor016c-player-state-sync.test.ts tests/refactor016-client-source.test.ts tests/room.test.ts --pool=threads --maxWorkers=1 --no-file-parallelism --testTimeout=30000 --hookTimeout=30000 --reporter=verbose',root);
      command('pnpm run test','pnpm run test',root);
      command('pnpm run build','pnpm run build',root);
      command('git diff --check','git diff --check',root);
    }
    console.log(`[${PATCH}] 적용과 검증이 성공했습니다.`);
    console.log(`[${PATCH}] 일반 방 플레이어·솔로 인간 1 + AI 7·로컬 HP/카메라 연결 경로 수정 완료.`);
    console.log(`[${PATCH}] 변경 전 백업: ${backupRoot}`);
  }catch(error){
    console.error(`[${PATCH}] 실패를 감지했습니다. 변경 파일을 적용 직전 상태로 자동 롤백합니다.`);
    for(const item of [...manifest].reverse()){
      const target=join(root,item.path),backup=join(backupRoot,'preimage',item.path);
      try{if(item.existed){mkdirSync(dirname(target),{recursive:true});copyFileSync(backup,target);}else rmSync(target,{force:true});}
      catch(rollbackError){console.error(`[${PATCH}] 롤백 실패: ${item.path}`,rollbackError);}
    }
    throw error;
  }
}finally{rmSync(tempRoot,{recursive:true,force:true});}
